{
  "citations": [
    {
      "span_start": 176,
      "span_end": 209,
      "span_text": "إِلاَّ عِبَادَكَ مِنْهُمُ الْمُخْلَصِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 262,
      "span_end": 335,
      "span_text": "فَالْحَقُّ وَالْحَقَّ أَقُولُ* لَأَمْلَأَنَّ جَهَنَّمَ مِنكَ وَمِمَّن تَبِعَكَ مِنْهُمْ أَجْمَعِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 400,
      "span_end": 477,
      "span_text": "إن الشيطان قد أيس أن يعبده المصلون في جزيرة العرب ولكن في التحريش بينهم",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 600,
      "span_end": 660,
      "span_text": "وَمَا كَانَ لِنَبِيٍّ أَن يَغُلَّ حَتَّى يُبَيِّنَ لِلنَّاسِ مَا أُرْسِلَ بِهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 800,
      "span_end": 862,
      "span_text": "رَبِّ بِمَآ أَغْوَيْتَنِي لأُزَيِّنَنَّ لَهُمْ فِي الأَرْضِ وَلأُغْوِيَنَّهُمْ أَجْمَعِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 863,
      "span_end": 896,
      "span_text": "إِلاَّ عِبَادَكَ مِنْهُمُ الْمُخْلَصِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 897,
      "span_end": 935,
      "span_text": "هَذَا صِرَاطٌ عَلَيَّ مُسْتَقِيمٌ",
      "citation_type": "Aya"
    },
    {
      "span_start": 935,
      "span_end": 1002,
      "span_text": "إِنَّ عِبَادِي لَيْسَ لَكَ عَلَيْهِمْ سُلْطَانٌ إِلاَّ مَنِ اتَّبَعَكَ مِنَ الْغَاوِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1020,
      "span_end": 1068,
      "span_text": "فَبِعِزَّتِكَ لَأُغْوِيَنَّهُمْ أَجْمَعِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1068,
      "span_end": 1101,
      "span_text": "إِلَّا عِبَادَكَ مِنْهُمُ الْمُخْلَصِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1102,
      "span_end": 1133,
      "span_text": "فَالْحَقُّ وَالْحَقَّ أَقُولُ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1133,
      "span_end": 1190,
      "span_text": "لَأَمْلَأَنَّ جَهَنَّمَ مِنكَ وَمِمَّن تَبِعَكَ مِنْهُمْ أَجْمَعِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1205,
      "span_end": 1264,
      "span_text": "قُلْ إِنَّ اللهَ يُضِلُّ مَنْ يَشَاءُ وَيَهْدِي إِلَيْهِ مَنْ أَنَابَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1270,
      "span_end": 1353,
      "span_text": "وَلَوْ شَاءَ اللهُ لَجَعَلَكُمْ أُمَّةً وَاحِدَةً وَلَكِنْ يُضِلُّ مَنْ يَشَاءُ وَيَهْدِي مَنْ يَشَاءُ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1358,
      "span_end": 1456,
      "span_text": "فَإِنَّ اللهَ يُضِلُّ مَنْ يَشَاءُ وَيَهْدِي إِلَيْهِ مَنْ يَشَاءُ فَلَا تَذْهَبْ نَفْسُكَ عَلَيْهِمْ حَسَرَاتٍ إِنَّ اللهَ عَلِيمٌ بِمَا يَصْنَعُونَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1460,
      "span_end": 1528,
      "span_text": "مَنْ يَشَأِ اللهُ يُضِلْهُ وَمَنْ يَشَأْ يَجْعَلْهُ عَلَى صِرَاطٍ مُسْتَقِيمٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1530,
      "span_end": 1566,
      "span_text": "وَمَا يُضِلُّ بِهِ إِلَّا الفَاسِقِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1570,
      "span_end": 1620,
      "span_text": "إِلَّا إِبْلِيسَ كَانَ مِنَ الجِنِّ فَفَسَقَ عَنْ أَمْرِ رَبِّهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1630,
      "span_end": 1688,
      "span_text": "فَبِمَا أَغْوَيْتَنِي لَأَقْعُدَنَّ لَهُمْ صِرَاطَكَ الْمُسْتَقِيمَ",
      "citation_type": "Aya"
    }
  ]
}
